[
  {
    "key": "KAN-5",
    "fields": {
      "summary": "Build PR Refinement agent (counter-voice to PR Review)",
      "description": {
        "content": [
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Description",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Create the PR Refinement agent: a daily cron job that reads inline comments posted by the PR Review agent and pushes back on comments that are wrong, over-eager, or low-signal.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Three files to create:",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/pr-refinement/prompt.md",
                "type": "text"
              },
              {
                "text": " — modeled on ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/pr-review/prompt.md",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/pr-refinement/README.md",
                "type": "text"
              },
              {
                "text": " — mirrors ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/pr-review/README.md",
                "type": "text"
              },
              {
                "text": " in structure",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".github/workflows/pr-refinement.yml",
                "type": "text"
              },
              {
                "text": " — daily cron sweep (not event-triggered); scans all open PRs that already have pr-review inline comments",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Note: pr-review (",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".github/workflows/pr-review.yml",
                "type": "text"
              },
              {
                "text": ") triggers on ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "pull_request",
                "type": "text"
              },
              {
                "text": " events; refinement runs its own daily cron.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Context",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "The PR Review + PR Refinement pair acts as a deliberate adversarial check: one model flags issues, a different model pushes back. This hedge against single-model review bias is a named design choice in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "docs/agentic-workflow.md",
                "type": "text"
              },
              {
                "text": " (Design choices). The pr-review workflow already exists at ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".github/workflows/pr-review.yml",
                "type": "text"
              },
              {
                "text": "; refinement is its complement.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Implementation notes",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "marks": [
                  {
                    "type": "strong"
                  }
                ],
                "text": "Model choice:",
                "type": "text"
              },
              {
                "text": " Use a different Claude model than pr-review's default (",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "anthropics/claude-code-action@v1",
                "type": "text"
              },
              {
                "text": " with no ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "--model",
                "type": "text"
              },
              {
                "text": " override). Specify via ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "claude_args: --model \u003cmodel-id\u003e",
                "type": "text"
              },
              {
                "text": " in the workflow. Verify current model IDs against Anthropic docs and document the choice and rationale in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/pr-refinement/README.md",
                "type": "text"
              },
              {
                "text": ".",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Acceptance Criteria",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "A PR that has pr-review inline comments receives a refinement pass that selectively pushes back on specific comments.",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "A PR that has reached the round cap is skipped in subsequent daily runs.",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "Run log committed under ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": ".github/agent-logs/pr-refinement/pr-\u003cPR_NUMBER\u003e/\u003cRUN_ID\u003e.json",
                        "type": "text"
                      },
                      {
                        "text": " — matching the convention in the \"Commit execution log\" step of ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": ".github/workflows/pr-review.yml",
                        "type": "text"
                      },
                      {
                        "text": ".",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              }
            ],
            "type": "bulletList"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Needs human input",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "[ ] Which stop condition should the refinement agent use to prevent re-processing the same PR indefinitely: (A) store a round counter as a PR label (e.g. ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": "refinement-rounds:N",
                        "type": "text"
                      },
                      {
                        "text": ") and skip the PR once it reaches a cap, or (B) freeze once a human has posted on the PR?",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              }
            ],
            "type": "bulletList"
          }
        ],
        "type": "doc",
        "version": 1
      },
      "labels": [],
      "resolution": {
        "name": ""
      },
      "issueType": {
        "id": "10004",
        "name": "Task",
        "subtask": false
      },
      "assignee": {
        "displayName": ""
      },
      "priority": {
        "name": "Medium"
      },
      "reporter": {
        "displayName": "Jae Yoon Bae"
      },
      "watches": {
        "isWatching": true,
        "watchCount": 1
      },
      "status": {
        "name": "DEVELOPMENT READY"
      },
      "components": [],
      "fixVersions": [],
      "versions": [],
      "comment": {
        "comments": [
          {
            "id": "10066",
            "author": {
              "accountId": "712020:3b310a89-3855-4959-9097-cc915405b62e",
              "emailAddress": "jaeyoonbae99@gmail.com",
              "displayName": "Jae Yoon Bae",
              "active": true
            },
            "body": {
              "content": [
                {
                  "attrs": {
                    "localId": "5bc64ae299ca"
                  },
                  "content": [
                    {
                      "text": "Yes, maybe let's try to track how many times it was refined, and then, based on that, stop. For now, I think one round would be sufficient, but it should be variable. ",
                      "type": "text"
                    }
                  ],
                  "type": "paragraph"
                }
              ],
              "type": "doc",
              "version": 1
            },
            "created": "2026-06-11T15:39:52.310+0200"
          }
        ],
        "total": 1
      },
      "Subtasks": [],
      "issueLinks": [],
      "created": "2026-06-05T14:13:24.923+0200",
      "updated": "2026-06-11T15:40:12.107+0200"
    }
  }
]

